import{_ as o,o as d,c as t,a3 as a}from"./chunks/framework.CRbjHCyB.js";const _=JSON.parse('{"title":"钩子机制","description":"","frontmatter":{},"headers":[],"relativePath":"zh/catter/design/hook-mechanism.md","filePath":"zh/catter/design/hook-mechanism.md"}'),c={name:"zh/catter/design/hook-mechanism.md"};function i(l,e,n,s,r,p){return d(),t("div",null,[...e[0]||(e[0]=[a(`<h1 id="钩子机制" tabindex="-1">钩子机制 <a class="header-anchor" href="#钩子机制" aria-label="Permalink to &quot;钩子机制&quot;">​</a></h1><p>钩子是 catter 最底层的组件。它是一个共享库，会被加载到构建系统生成的每个进程中。它的唯一职责是拦截进程创建调用，并将其重写，使每个子进程都通过 <code>catter-proxy</code> 中转，而非直接执行。</p><p>钩子的实现完全依赖于平台特性。Unix 和 Windows 使用了截然不同的拦截技术。</p><h2 id="unix-linux-与-macos-基于-ld-preload-的拦截" tabindex="-1">Unix（Linux 与 macOS）-- 基于 LD_PRELOAD 的拦截 <a class="header-anchor" href="#unix-linux-与-macos-基于-ld-preload-的拦截" aria-label="Permalink to &quot;Unix（Linux 与 macOS）-- 基于 LD_PRELOAD 的拦截&quot;">​</a></h2><p>Unix 钩子是通过动态链接器的预加载机制加载的共享库：</p><ul><li><strong>Linux</strong>: <code>libcatter-hook-unix.so</code>，通过 <code>LD_PRELOAD</code> 加载</li><li><strong>macOS</strong>: <code>libcatter-hook-unix.dylib</code>，通过 <code>DYLD_INSERT_LIBRARIES</code> 加载</li></ul><h3 id="被拦截的函数" tabindex="-1">被拦截的函数 <a class="header-anchor" href="#被拦截的函数" aria-label="Permalink to &quot;被拦截的函数&quot;">​</a></h3><p>钩子替换了所有用于创建新进程的标准 POSIX 函数：</p><p><strong>exec 系列</strong>:</p><ul><li><code>execve()</code>、<code>execv()</code></li><li><code>execvpe()</code>、<code>execvp()</code>、<code>execvP()</code></li><li><code>execl()</code>、<code>execlp()</code>、<code>execle()</code></li></ul><p><strong>posix_spawn 系列</strong>:</p><ul><li><code>posix_spawn()</code></li><li><code>posix_spawnp()</code></li></ul><p>在 Linux 上，钩子使用 <code>dlsym(RTLD_NEXT, &quot;execve&quot;)</code> 从加载顺序中的下一个库获取原始函数指针，然后提供一个签名相同的替换函数。当替换函数被调用时，钩子可以检查和修改参数，然后选择性地调用原始函数。</p><p>在 macOS 上，钩子使用 <code>DYLD_INTERPOSE</code> 宏在 dyld 层面替换函数，这是该平台上的首选技术。</p><h3 id="核心类" tabindex="-1">核心类 <a class="header-anchor" href="#核心类" aria-label="Permalink to &quot;核心类&quot;">​</a></h3><p>钩子由一组协作的类实现：</p><ul><li><strong><code>Session</code></strong> -- 从环境变量中读取并存储会话信息。提供代理路径和父进程会话 ID。</li><li><strong><code>Resolver</code></strong> -- 解析目标可执行文件的路径。处理 PATH 查找、相对路径解析及可执行文件缺失等边界情况。</li><li><strong><code>CmdBuilder</code></strong> -- 构造重写后的命令，将 <code>catter-proxy</code> 替换原始可执行文件。</li><li><strong><code>EnvGuard</code></strong> -- RAII 守卫，在调用真正的 <code>execve</code> 之前清理环境。移除 catter 相关变量，并从 <code>LD_PRELOAD</code> 中剥离钩子库。</li><li><strong><code>Executor</code></strong> -- 协调整个拦截过程。验证会话、解析可执行文件、构建代理命令、清理环境、调用原始函数。</li><li><strong><code>Linker</code></strong> -- 真实系统调用的抽象层。封装 <code>dlsym(RTLD_NEXT, ...)</code> 以调用原始的 <code>execve</code> 或 <code>posix_spawn</code>。</li></ul><h3 id="钩子初始化" tabindex="-1">钩子初始化 <a class="header-anchor" href="#钩子初始化" aria-label="Permalink to &quot;钩子初始化&quot;">​</a></h3><p>钩子库通过动态链接器的构造函数机制（<code>__attribute__((constructor))</code> 或等效方式）加载。初始化期间，库会：</p><ol><li>设置日志（输出到 catter 数据目录下的 <code>log/catter-hook.log</code>）</li><li>准备就绪等待拦截 -- <code>Executor</code> 在首次拦截时惰性读取环境中的会话状态</li></ol><h3 id="环境变量" tabindex="-1">环境变量 <a class="header-anchor" href="#环境变量" aria-label="Permalink to &quot;环境变量&quot;">​</a></h3><p>钩子从以下环境变量中读取会话信息，这些变量由代理在启动构建命令时设置：</p><table tabindex="0"><thead><tr><th>变量</th><th>用途</th></tr></thead><tbody><tr><td><code>__key_catter_proxy_path_v1</code></td><td><code>catter-proxy</code> 二进制文件的绝对路径</td></tr><tr><td><code>__key_catter_command_id_v1</code></td><td>父进程的会话 ID</td></tr></tbody></table><h3 id="拦截流程" tabindex="-1">拦截流程 <a class="header-anchor" href="#拦截流程" aria-label="Permalink to &quot;拦截流程&quot;">​</a></h3><p>当任何进程创建函数被调用时（例如 <code>execve(&quot;/usr/bin/g++&quot;, argv, envp)</code>）：</p><ol><li><p>进入钩子的替换函数。</p></li><li><p><strong><code>Executor</code></strong> 验证会话。如果会话无效（缺少环境变量），它会构建一个错误命令，将问题报告给守护进程。</p></li><li><p><strong><code>Resolver</code></strong> 将目标可执行文件解析为绝对路径。对于 <code>execvp()</code> 和 <code>execvpe()</code> 等函数，它会搜索 <code>PATH</code> 中的目录。对于 <code>execve()</code>，则相对于当前目录解析。</p></li><li><p><strong><code>CmdBuilder</code></strong> 构造代理命令：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;proxy_path&gt; -p &lt;self_id&gt; --exec &lt;resolved_path&gt; -- &lt;original_argv...&gt;</span></span></code></pre></div><p>原始的 <code>argv[0]</code> 及所有后续参数保留在 <code>--</code> 分隔符之后。</p></li><li><p><strong><code>EnvGuard</code></strong>（RAII）修改环境数组：</p><ul><li>移除 <code>__key_catter_proxy_path_v1</code> 和 <code>__key_catter_command_id_v1</code></li><li>从 <code>LD_PRELOAD</code>（或 <code>DYLD_INSERT_LIBRARIES</code>）中剥离钩子库名称</li><li>如果剥离后 <code>LD_PRELOAD</code> 变为空，则将其完全移除</li></ul></li><li><p><strong><code>Linker</code></strong> 使用重写后的命令调用<strong>真正的</strong> <code>execve()</code>（通过 <code>dlsym(RTLD_NEXT, ...)</code> 获取）。</p></li><li><p>如果 <code>execve</code> 成功，当前进程镜像被替换，函数不会返回。如果失败，钩子恢复 <code>errno</code> 并将错误返回给调用者。</p></li></ol><h3 id="为什么要清理环境" tabindex="-1">为什么要清理环境？ <a class="header-anchor" href="#为什么要清理环境" aria-label="Permalink to &quot;为什么要清理环境？&quot;">​</a></h3><p>这一步至关重要。如果在启动 <code>catter-proxy</code> 时钩子库仍留在 <code>LD_PRELOAD</code> 中：</p><ol><li><code>catter-proxy</code> 本身会被钩住</li><li>当代理尝试执行实际的编译器时，钩子会拦截该调用</li><li>钩子会将其重写为启动另一个 <code>catter-proxy</code></li><li>这将造成<strong>无限递归</strong></li></ol><p>通过从 <code>LD_PRELOAD</code> 中剥离钩子，代理可以不受拦截地执行。代理仅在以 <code>INJECT</code> 动作启动命令时才重新添加 <code>LD_PRELOAD</code>，确保钩子仅挂载到正确的进程上。</p><h3 id="递归钩子" tabindex="-1">递归钩子 <a class="header-anchor" href="#递归钩子" aria-label="Permalink to &quot;递归钩子&quot;">​</a></h3><p>由于 <code>LD_PRELOAD</code> 通过环境变量被子进程继承，拦截是自动递归的。考虑如下构建场景：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>make</span></span>
<span class="line"><span>  -&gt; sh -c &quot;gcc main.c -o main&quot;</span></span>
<span class="line"><span>     -&gt; gcc main.c -o main</span></span>
<span class="line"><span>        -&gt; cc1 main.c -o main.s</span></span>
<span class="line"><span>        -&gt; as main.s -o main.o</span></span>
<span class="line"><span>        -&gt; ld main.o -o main</span></span></code></pre></div><p>这棵进程树中的每个进程都继承了 <code>LD_PRELOAD</code>，因此都会被钩住。每次调用都会经过 <code>catter-proxy</code>，由守护进程决定如何处理。构建系统完全无法感知到拦截的存在。</p><hr><h2 id="windows-dll-注入与-api-钩子" tabindex="-1">Windows -- DLL 注入与 API 钩子 <a class="header-anchor" href="#windows-dll-注入与-api-钩子" aria-label="Permalink to &quot;Windows -- DLL 注入与 API 钩子&quot;">​</a></h2><p>Windows 钩子使用了与 Unix 完全不同的方法，因为 Windows 没有 <code>LD_PRELOAD</code> 的等价机制。catter 结合使用了：</p><ol><li><strong>DLL 注入</strong> -- 将钩子库加载到目标进程中</li><li><strong>基于 MinHook 的 API 钩子</strong> -- 在这些进程内拦截 <code>CreateProcess</code> 调用</li></ol><h3 id="钩子-dll" tabindex="-1">钩子 DLL <a class="header-anchor" href="#钩子-dll" aria-label="Permalink to &quot;钩子 DLL&quot;">​</a></h3><p>钩子编译为 <code>catter-hook-win64.dll</code>。它使用 MinHook -- 一个轻量级的 x86/x64 API 钩子库，通过覆写目标函数的前几个字节为跳转指令（trampoline hooking）来实现函数替换。</p><h3 id="环境变量-1" tabindex="-1">环境变量 <a class="header-anchor" href="#环境变量-1" aria-label="Permalink to &quot;环境变量&quot;">​</a></h3><table tabindex="0"><thead><tr><th>变量</th><th>用途</th></tr></thead><tbody><tr><td><code>CATTER_IPC_ID</code></td><td>父进程的会话 ID</td></tr><tr><td><code>CATTER_PROXY_PATH</code></td><td><code>catter-proxy.exe</code> 的绝对路径</td></tr></tbody></table><h3 id="dll-注入过程" tabindex="-1">DLL 注入过程 <a class="header-anchor" href="#dll-注入过程" aria-label="Permalink to &quot;DLL 注入过程&quot;">​</a></h3><p>当 <code>catter-proxy</code>（注入模式）需要启动挂载了钩子的构建命令时：</p><ol><li><p><strong>以挂起状态创建目标进程</strong>。代理调用 <code>CreateProcessA()</code>，使用 <code>CREATE_SUSPENDED</code> 标志。进程被创建但主线程不会运行。</p></li><li><p><strong>设置环境变量</strong>。<code>CATTER_IPC_ID</code> 和 <code>CATTER_PROXY_PATH</code> 在创建进程前通过环境块传入目标进程。</p></li><li><p><strong>在目标进程中分配内存</strong>。代理调用 <code>VirtualAllocEx()</code> 在目标进程的地址空间中分配一块内存区域。</p></li><li><p><strong>写入 DLL 路径</strong>。代理调用 <code>WriteProcessMemory()</code> 将 <code>catter-hook-win64.dll</code> 的完整路径写入分配的内存。</p></li><li><p><strong>创建远程线程加载 DLL</strong>。代理按顺序尝试三种方法：</p><ul><li><code>CreateRemoteThread()</code> -- 已公开的 Win32 API。首先尝试，因为它是最广泛支持的方法。</li><li><code>NtCreateThreadEx()</code> -- 未公开的 NT API。备选方案，在现代 Windows（Vista+）上可靠运行。</li><li><code>RtlCreateUserThread()</code> -- 另一个未公开的 NT API。最后的备选方案。</li></ul><p>远程线程的入口点是 <code>LoadLibraryA</code>，其参数是步骤 4 中写入的 DLL 路径字符串的指针。当线程运行时，它将 <code>catter-hook-win64.dll</code> 加载到目标进程中。</p></li><li><p><strong>等待注入完成</strong>。代理等待远程线程执行完毕（超时时间为 3 秒）。</p></li><li><p><strong>恢复主线程</strong>。代理调用 <code>ResumeThread()</code> 让目标进程开始执行。此时钩子 DLL 已加载，钩子函数已激活。</p></li></ol><h3 id="被钩住的-windows-api" tabindex="-1">被钩住的 Windows API <a class="header-anchor" href="#被钩住的-windows-api" aria-label="Permalink to &quot;被钩住的 Windows API&quot;">​</a></h3><p>钩子 DLL 在 <code>DLL_PROCESS_ATTACH</code> 期间使用 MinHook 的 trampoline 机制安装钩子：</p><ul><li><strong><code>CreateProcessA()</code></strong> -- ANSI 版本的进程创建函数</li><li><strong><code>CreateProcessW()</code></strong> -- 宽字符版本的进程创建函数</li><li><strong><code>CreateProcessAsUserA()</code></strong> -- 透传（当前未重写命令行）</li><li><strong><code>CreateProcessAsUserW()</code></strong> -- 透传（当前未重写命令行）</li></ul><p>MinHook 的工作原理：</p><ol><li>保存目标函数的前几条指令</li><li>将其覆写为跳转到替代函数的指令</li><li>提供一个 trampoline（跳板），包含保存的指令及跳回原函数的跳转，使原始函数仍可被调用</li></ol><h3 id="钩子替代逻辑" tabindex="-1">钩子替代逻辑 <a class="header-anchor" href="#钩子替代逻辑" aria-label="Permalink to &quot;钩子替代逻辑&quot;">​</a></h3><p>当被钩住的进程调用 <code>CreateProcessA</code> 或 <code>CreateProcessW</code> 时：</p><ol><li><p><strong>提取命令行</strong>。钩子读取 <code>lpApplicationName</code> 和 <code>lpCommandLine</code>。</p></li><li><p><strong>解析绝对路径</strong>。钩子使用 <code>resolve_abspath()</code> 解析可执行文件路径，搜索程序目录、当前目录、System32、Windows 目录和 <code>PATH</code>（与标准 Windows 搜索顺序一致）。</p></li><li><p><strong>重写命令行</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>{proxy_path} -p {ipc_id} --exec {resolved_path} -- {original_cmdline}</span></span></code></pre></div><p><code>lpApplicationName</code> 被设为 <code>nullptr</code>，使 <code>CreateProcess</code> 正常解析命令行。</p></li><li><p><strong>通过 MinHook trampoline 调用原始 <code>CreateProcess</code></strong>，传入修改后的命令行。</p></li></ol><h3 id="与-unix-的关键区别" tabindex="-1">与 Unix 的关键区别 <a class="header-anchor" href="#与-unix-的关键区别" aria-label="Permalink to &quot;与 Unix 的关键区别&quot;">​</a></h3><p>在 Unix 上，<code>LD_PRELOAD</code> 是一个由所有子进程自动继承的环境变量。钩子默认具有&quot;传染性&quot; -- 每个子进程都会被钩住。</p><p>在 Windows 上没有这样的机制。钩子 DLL 必须显式注入到每个新进程中。这通过以下方式实现：</p><ol><li>钩子的 <code>CreateProcess</code> 替代函数拦截每次进程创建</li><li>将命令重写为通过 <code>catter-proxy</code> 中转</li><li>当代理决定以 <code>INJECT</code> 动作执行时，它对新进程执行 DLL 注入（创建挂起、注入、恢复）</li></ol><p>这意味着代理负责在每一代子进程中重新注入钩子，维持递归拦截链。</p><h3 id="dll-生命周期" tabindex="-1">DLL 生命周期 <a class="header-anchor" href="#dll-生命周期" aria-label="Permalink to &quot;DLL 生命周期&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>DLL_PROCESS_ATTACH:</span></span>
<span class="line"><span>  MH_Initialize()       -- 初始化 MinHook</span></span>
<span class="line"><span>  MH_CreateHook(...)    -- 在 CreateProcess 系列函数上安装钩子</span></span>
<span class="line"><span>  MH_EnableHook(...)    -- 激活所有钩子</span></span>
<span class="line"><span></span></span>
<span class="line"><span>DLL_PROCESS_DETACH:</span></span>
<span class="line"><span>  MH_DisableHook(...)   -- 停用所有钩子</span></span>
<span class="line"><span>  MH_Uninitialize()     -- 清理 MinHook</span></span></code></pre></div><p>在 attach 阶段调用 <code>DisableThreadLibraryCalls()</code> 以抑制 <code>DLL_THREAD_ATTACH</code> 和 <code>DLL_THREAD_DETACH</code> 通知，减少运行开销。</p><h2 id="平台对比" tabindex="-1">平台对比 <a class="header-anchor" href="#平台对比" aria-label="Permalink to &quot;平台对比&quot;">​</a></h2><table tabindex="0"><thead><tr><th>方面</th><th>Linux</th><th>macOS</th><th>Windows</th></tr></thead><tbody><tr><td>钩子库</td><td><code>libcatter-hook-unix.so</code></td><td><code>libcatter-hook-unix.dylib</code></td><td><code>catter-hook-win64.dll</code></td></tr><tr><td>注入方式</td><td><code>LD_PRELOAD</code> 环境变量</td><td><code>DYLD_INSERT_LIBRARIES</code> 环境变量</td><td><code>VirtualAllocEx</code> + <code>LoadLibraryA</code></td></tr><tr><td>函数替换</td><td><code>dlsym(RTLD_NEXT, ...)</code></td><td><code>DYLD_INTERPOSE</code> 宏</td><td>MinHook trampoline 钩子</td></tr><tr><td>拦截的 API</td><td><code>execve</code>、<code>execvp</code>、<code>posix_spawn</code> 等</td><td>与 Linux 相同</td><td><code>CreateProcessA</code>、<code>CreateProcessW</code></td></tr><tr><td>递归钩子</td><td>自动（环境变量继承）</td><td>自动（环境变量继承）</td><td>显式（每个进程重新注入 DLL）</td></tr><tr><td>会话环境变量</td><td><code>__key_catter_proxy_path_v1</code>、<code>__key_catter_command_id_v1</code></td><td>与 Linux 相同</td><td><code>CATTER_PROXY_PATH</code>、<code>CATTER_IPC_ID</code></td></tr></tbody></table>`,63)])])}const g=o(c,[["render",i]]);export{_ as __pageData,g as default};
